import { buildPilotSummary, normaliseMinutes, safeStatistics } from '../shared/safe-export.js';

await window.GHRAB.accessReady;
if (window.GHRAB.isAdmin()) {
const G=window.GHRAB;
const $=s=>document.querySelector(s);
let apps=[];
const WEEK_KEY='ghrab.pilot.week';
const phases=[{from:1,to:2,title:['Start a bezpečnost','Launch and safety'],text:['Výběr účastníků, školení, anonymizace a první jednoduchý úkol.','Select participants, provide training, set anonymisation rules and complete a first task.']},{from:3,to:5,title:['Běžné používání','Regular use'],text:['Reálná příprava do výuky, evidence nejasností a měření úspory času.','Real lesson preparation, logging unclear points and measuring time saved.']},{from:6,to:6,title:['Průběžné vyhodnocení','Interim review'],text:['Opravy, zjednodušení a výběr nejcennějších funkcí.','Fixes, simplification and selection of the most valuable features.']},{from:7,to:9,title:['Propojený pracovní postup','Connected workflow'],text:['Diferenciace, test, LUDUS a bezpečná komunikace z jednoho balíčku.','Differentiation, testing, LUDUS and safe communication from one package.']},{from:10,to:12,title:['Opakované použití a rozhodnutí','Repeated use and decision'],text:['Případové studie, souhrn přínosu a rozhodnutí o profesionálním provozu.','Case studies, impact summary and a decision on professional operation.']}];
function labelEvent(e){const outcomes={success:['Povedlo se','Successful'],partial:['Částečně','Partly successful'],problem:['Problém','Problem'],idea:['Nápad','Idea']};const types={handoff:['Předání materiálu','Material handoff'],'material-saved':['Uložení materiálu','Resource saved'],'material-exported':['Export materiálu','Resource export'],'ludus-export':['Export LUDUS','LUDUS export'],session:['Pilotní záznam','Pilot entry']};return G.t(...(outcomes[e.result]||types[e.type]||[e.type,e.type]))}
function appName(id){return G.localised(apps.find(a=>a.id===id)?.name)||G.t('Obecně','General')}
function metrics(){const events=G.getPilotEvents(),launches=G.getLaunches(),workspace=G.getWorkspace();return{events,launches,workspace,...safeStatistics({events,launches,workspace})}}
function hours(value){return Math.round(Number(value||0)/60*10)/10}
function renderKpis(){const m=metrics();const host=$('#pilot-kpis');const vals=[[m.launchCount,G.t('spuštění ze Studia v tomto prohlížeči','launches from the Studio in this browser')],[m.materialCount,G.t('místních materiálů','local resources')],[m.handoffs,G.t('předání mezi aplikacemi','application handoffs')],[hours(m.reportedMinutes),G.t('hodin vykázaných učiteli','teacher-reported hours')],[hours(m.estimatedMinutes),G.t('hodin orientačního odhadu (doplňkově)','indicative estimated hours (supplementary)')],[m.averageRating?m.averageRating.toFixed(1):'—',G.t('průměrná užitečnost','average usefulness')]];host.replaceChildren(...vals.map(([v,l])=>{const a=document.createElement('article');a.className='pilot-kpi';const strong=document.createElement('strong');strong.textContent=String(v);const span=document.createElement('span');span.textContent=l;a.append(strong,span);return a}))}
function renderTimeline(){const week=Math.max(1,Math.min(12,Number($('#pilot-week').value||1)));G.safeSetItem(WEEK_KEY,String(week),{silent:true});const host=$('#pilot-timeline');host.replaceChildren(...phases.map(p=>{const item=document.createElement('article');item.className='timeline-item';if(week>p.to)item.classList.add('complete');else if(week>=p.from)item.classList.add('current');const w=document.createElement('div');w.className='timeline-week';w.textContent=p.from===p.to?`${G.t('Týden','Week')} ${p.from}`:`${G.t('Týdny','Weeks')} ${p.from}–${p.to}`;const d=document.createElement('div');const h=document.createElement('h2');h.textContent=G.t(...p.title);const text=document.createElement('p');text.textContent=G.t(...p.text);d.append(h,text);item.append(w,d);return item}))}
function renderEvents(){const list=G.getPilotEvents().slice().reverse().slice(0,20),host=$('#pilot-events');if(!list.length){host.innerHTML=`<div class="empty-state">${G.t('Zatím nejsou žádné pilotní záznamy.','There are no pilot entries yet.')}</div>`;return}host.replaceChildren(...list.map(e=>{const row=document.createElement('article');row.className=`pilot-event result-${e.result||'auto'}`;const top=document.createElement('div');const strong=document.createElement('strong');strong.textContent=labelEvent(e);const time=document.createElement('time');time.textContent=new Date(e.at).toLocaleString(G.state.language==='cs'?'cs-CZ':'en-GB');top.append(strong,time);const p=document.createElement('p');p.textContent=[appName(e.appId), e.note ? G.t('poznámka uložena jen lokálně','note stored locally only') : null].filter(Boolean).join(' · ');const minutes=normaliseMinutes(e);const meta=document.createElement('small');meta.textContent=[minutes.reportedMinutes?`${minutes.reportedMinutes} min · ${G.t('vykázáno','reported')}`:null,minutes.estimatedMinutes?`${minutes.estimatedMinutes} min · ${G.t('automatický odhad','automatic estimate')}`:null,e.rating?`${G.t('užitečnost','usefulness')} ${e.rating}/5`:null].filter(Boolean).join(' · ');row.append(top,p,meta);return row}))}
function render(){renderKpis();renderTimeline();renderEvents()}
function fillApps(){const sel=$('#pilot-app');sel.replaceChildren();const general=document.createElement('option');general.value='';general.textContent=G.t('Obecně / AI Studio','General / AI Studio');sel.append(general,...apps.map(a=>{const o=document.createElement('option');o.value=a.id;o.textContent=G.localised(a.name);return o}))}
$('#pilot-add').addEventListener('click',()=>{const note=$('#pilot-note').value.trim();const saved=G.recordPilotEvent({type:'session',appId:$('#pilot-app').value||null,result:$('#pilot-result').value,reportedMinutes:Number($('#pilot-minutes').value||0),rating:Number($('#pilot-rating').value||0),note});if(!saved)return;$('#pilot-note').value='';$('#pilot-minutes').value='0';render();G.showToast(G.t('Anonymní pilotní záznam byl uložen.','The anonymous pilot entry was saved.'))});
$('#pilot-week').value=G.safeGetItem(WEEK_KEY)||'1';$('#pilot-week').addEventListener('input',renderTimeline);
$('#export-pilot').addEventListener('click',()=>{G.downloadJson(buildPilotSummary({portalVersion:G.VERSION,currentWeek:Number($('#pilot-week').value),launches:G.getLaunches(),events:G.getPilotEvents(),workspace:G.getWorkspace()}),`ghrab-pilot-anonymni-souhrn-${new Date().toISOString().slice(0,10)}.json`)});
$('#reset-pilot').addEventListener('click',()=>{if(confirm(G.t('Opravdu vymazat místní spuštění, události a nastavení týdne? Materiály v pracovním prostoru zůstanou zachovány.','Clear local launches, events and week setting? Workspace resources will remain.'))){G.safeRemoveItem('ghrab.pilot.launches');G.clearPilotEvents();G.safeRemoveItem(WEEK_KEY);$('#pilot-week').value='1';render()}});
document.addEventListener('ghrab:language',()=>{fillApps();render()});document.querySelector('[data-nav="pilot"]')?.setAttribute('aria-current','page');G.loadApps().then(x=>{apps=x;fillApps();render()});render();
}
